/bin/sh -lc "cat > /workspace/work/final_result.json << 'JSONEOF'
{
  \"anomaly_ids\": [\"ANOM-DUP-001\"],
  \"record_ids\": [\"R000020\", \"R004203\"],
  \"answer\": \"以R000020为线索核查发现员工E0028（杜丹，财务管理部）将同一张发票FP202500000020（XX供应商2706，金额669.5元，住宿费）在两条报销记录R000020（报销日期2025-01-05，报销金额669.5元）和R004203（报销日期2025-04-10，报销金额669.5元）中重复提交并均获批准报销，构成重复报销。两次报销事由均为'财务管理部跨部门协同赴杭州住宿费'，发票日期均为2025-01-05，属于同一经济事项使用同一发票重复报销，违反了《XX证券费用报销管理办法(2025修订版)》第十条'同一发票最多报销1次'的规定。两次报销均经同一审批人E0009（部门经理）审批通过，内部控制存在缺陷。\",
  \"citations\": [
    {\"doc_id\": \"01_expense_reimbursement_2025.md\", \"clause_no\": \"第十条\"}
  ]
}
JSONEOF
echo \"final_result.json written\""

/bin/sh -lc "cat > /workspace/work/final_result.json << 'JSONEOF'
{
  \"anomaly_ids\": [\"ANOM-DUP-001\"],
